c.PRAC_AR_NBR PRAC_AR_NBR,ewt42ofprac.CRP_1_ACTV_ACRG CRP_1_ACTV_ACRG,ewt42ofprac.PRAC_LAND_STAT_CD PRAC_LAND_STAT_CD,ewt42ofprac.OFR_CLU_ID OFR_CLU_ID,ewt42ofprac.PRAC_LAND_TYPE_CD PRAC_LAND_TYPE_CD,ewt42ofprac.MPL_ACRG MPL_ACRG,ewt42ofprac.pvt_irr_crnr_ind PVT_IRR_CRNR_IND,ewt42ofprac.cpld_acrg CPLD_ACRG,ewt40ofrsc.CNSV_CTR_SEQ_NBR CNSV_CTR_SEQ_NBR,ewt40ofrsc.CNSV_CTR_SUFX_CD CNSV_CTR_SFX_CD,ewt42ofprac.OFR_SCNR_ID OFR_SCNR_ID,EWT42OFPRAC.NCPLD_ACRG NCPLD_ACRG,EWT42OFPRAC.WLHD_ACRG WLHD_ACRG,EWT42OFPRAC.IFBL_TO_FARM_ACRG IFSBL_TO_FARM_ACRG,EWT42OFPRAC.CRP_EXPR_CPLD_ACRG CRP_EXPR_CPLD_ACRG,EWT42OFPRAC.CRP_EXPR_NCPLD_ACRG CRP_EXPR_NCPLD_ACRG,EWT42OFPRAC.CRP_EXPR_MPL_ACRG CRP_EXPR_MPL_ACRG,EWT42OFPRAC.GRP_EXPR_CPLD_ACRG GRP_EXPR_CPLD_ACRG,EWT42OFPRAC.GRP_EXPR_NCPLD_ACRG GRP_EXPR_NCPLD_ACRG,EWT42OFPRAC.PRAC_INCTV_RT PRAC_INCTV_RT,EWT42OFPRAC.CRP_EXPR_WLHD_ACRG CRP_EXPR_WLHD_ACRG,EWT42OFPRAC.CRP_EXPR_IFBL_TO_FARM_ACRG CRP_EXPR_IFSBL_TO_FARM_ACRG,ewt42ofprac.DATA_STAT_CD DATA_STAT_CD,ewt42ofprac.CRE_DT CRE_DT,ewt42ofprac.LAST_CHG_DT LAST_CHG_DT,ewt42ofprac.LAST_CHG_USER_NM LAST_CHG_USER_NM,ewt42ofprac.CNSV_ELG_AREA_CD CNSV_ELG_AREA_CD,ewt42ofprac.clu_hist_nbr clu_hist_nbr,EWT42OFPRAC.crp_acre_rent_rdn_cd CRP_ACRE_RENT_RDN_CD,EWT42OFPRAC.ifsbl_to_farm_prac_inctv_rt IFSBL_TO_FARM_PRAC_INCTV_RT,-- op,1 AS TBL_PRIORITYFROM "fsa-prod-cnsv".EWT42OFPRAC LEFT JOIN "fsa-prod-cnsv".EWT40OFRSC ON (EWT42OFPRAC.OFR_SCNR_ID = EWT40OFRSC.OFR_SCNR_ID) LEFT JOIN "fsa-prod-cnsv".EWT14SGNP ON (EWT40OFRSC.SGNP_ID = EWT14SGNP.SGNP_ID)--WHERE __CDC_OPERATION <> 'D'

