42ofprac.CRE_DT CRE_DT,ewt42ofprac.LAST_CHG_DT LAST_CHG_DT,ewt42ofprac.LAST_CHG_USER_NM LAST_CHG_USER_NM,ewt42ofprac.CNSV_ELG_AREA_CD CNSV_ELG_AREA_CD,ewt42ofprac.clu_hist_nbr clu_hist_nbr,EWT42OFPRAC.crp_acre_rent_rdn_cd CRP_ACRE_RENT_RDN_CD,EWT42OFPRAC.ifsbl_to_farm_prac_inctv_rt IFSBL_TO_FARM_PRAC_INCTV_RT,-- op,2 AS TBL_PRIORITYFROM "fsa-prod-cnsv".EWT40OFRSC JOIN "fsa-prod-cnsv".EWT42OFPRAC ON (EWT40OFRSC.OFR_SCNR_ID = EWT42OFPRAC.OFR_SCNR_ID) LEFT JOIN "fsa-prod-cnsv".EWT14SGNP ON (EWT40OFRSC.SGNP_ID = EWT14SGNP.SGNP_ID)--WHERE __CDC_OPERATION <> 'D'UNIONSELECT ewt40ofrsc.PGM_YR PGM_YR,ewt40ofrsc.ADM_ST_FSA_CD ADM_ST_FSA_CD,ewt40ofrsc.ADM_CNTY_FSA_CD ADM_CNTY_FSA_CD,ewt40ofrsc.TR_NBR TR_NBR,ewt40ofrsc.OFR_SCNR_NM OFR_SCNR_NM,ewt14sgnp.SGNP_TYPE_DESC SGNP_TYPE_DESC,ewt14sgnp.SGNP_STYPE_DESC SGNP_STYPE_DESC,ewt14sgnp.SGNP_NBR SGNP_NBR,ewt14sgnp.SGNP_STYPE_AGR_NM SGNP_STYPE_AGR_NM,ewt42ofprac.FLD_NBR FLD_NBR,ewt42ofprac.CNSV_PRAC_CD CNSV_PRAC_CD,ewt40ofrsc.FARM_NBR FARM_NBR,ewt42ofprac.PRAC_SEQ_NBR PRAC_SEQ_NBR,ewt42ofprac.ST_FSA_CD ST_FSA_CD,ewt42ofprac.CNTY_FSA_CD CNTY_FSA_CD,ewt42ofprac.PRAC_ACRG PRAC_ACRG,ewt42ofprac.COST_SHR_EST_AMT COST_SHR_EST_AMT,ewt42ofprac.CRP_PRAC_YR_CT CRP_PRAC_YR_CT,ewt42ofprac.HARD_TREE_PLNT_IND HDWD_TREE_PLNT_IND,ewt42ofprac.LONG_LEAF_PINE_IND LONG_LEAF_PINE_IND,ewt42ofprac.CP12_ACRG CP12_ACRG,ewt42ofprac.PRAC_MNT_RT PRAC_MNT_RT,ewt42ofprac.CRP_SIP_AMT CRP_SIP_AMT,ewt42ofprac.CRP_PIP_AMT CRP_PIP_AMT,ewt42ofprac.PRAC_RT_CAT_DESC PRAC_RT_CAT_DESC,ewt42ofprac.PRAC_AR_NBR PRAC_AR_NBR,ewt42ofprac.CRP_1_ACTV_ACRG CRP_1_ACTV_ACRG,ewt42ofprac.PRAC_LAND_STAT_CD PRAC_LAND_STAT_CD,ewt42ofprac.OFR_CLU_ID OFR_CLU_ID,ewt42ofprac.PRAC_LAND_TYPE_CD PRAC_LAND_TYPE_CD,ewt42ofprac.MPL_ACRG MPL_ACRG,ewt42ofprac.pvt_irr_crnr_ind PVT_IRR_CRNR_IND,ewt42ofprac.cpld_acrg CPLD_ACRG,ewt40ofrsc.CNSV_CTR_SEQ_NBR CNSV_CTR_SEQ_NBR,ewt40ofrsc.CNSV_CTR_SUFX_CD CNSV_CTR_SFX_CD,ewt42ofprac.OFR_SCNR_ID OFR_SCNR_ID,E